tokens.customizationCode:
/* Largura customizada por side */
[data-slot="sheet-content"][data-side="right"],
[data-slot="sheet-content"][data-side="left"] {
  width: 400px;
}
@media (min-width: 640px) {
  [data-slot="sheet-content"][data-side="right"],
  [data-slot="sheet-content"][data-side="left"] {
    max-width: 540px;
  }
}

